{
  "name": "Medicare Savings Programs (QMB, SLMB, QI)",
  "eligibility": {
    "age": 65,
    "income_limits": "Hawaii uses higher limits than federal standards. Federal base for 2026 (with $20 disregard): QMB individual $1,350/month, couple $1,824/month; SLMB individual $1,616/month, couple $2,184/month; QI individual ~$1,823/month (135% FPL), couple ~$2,463/month. Hawaii limits slightly higher; older sources cite QMB individual $1,550/month, couple $2,095/month. Limits apply monthly; vary by program tier (QMB <100% FPL, SLMB 100-120% FPL, QI 120-135% FPL). No full household size table beyond couple; contact state for exact current figures as they adjust annually.[5][6][7]",
    "asset_limits": "Individual: $9,950; Couple: $14,910 (2026 federal/Hawaii limits). Counts: Bank accounts, stocks (some exempt). Exempt: Primary home, one vehicle, household items, engagement/wedding rings, burial plots/expenses up to $1,500, life insurance < $1,500 cash value, certain Native American payments/stocks. Hawaii may disregard more resources per federal allowance.[3][4][5][6]",
    "other_requirements": ["Must have Medicare Part A (free for most over 65); US citizen/resident; Hawaii resident; not eligible for full Medicaid for QI; QI first-come-first-served and annual reapplication with priority to prior enrollees."]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Part A premium (if applicable), Part B premium (~$202.90/month 2026), Part A deductible ($1,484+ annually), Part B deductible ($203+), coinsurance/copayments. SLMB: Part B premium only. QI: Part B premium only. All auto-qualify for Extra Help (low/no cost Part D drugs). No direct services; pays costs to Medicare.[1][4][6][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: medquest.hawaii.gov (MedQUEST portal)", "Phone: Hawaii MedQUEST at 1-800-316-8005", "Mail/In-person: Local MedQUEST district offices (e.g., Oahu: 601 Kamokila Blvd, Kapolei)", "Through SHIP counselor: hawaiiship.org"],
    "processing_time": "Typically 45 days; no specific Hawaii data.",
    "waitlist": "QI: First-come, first-served with funding caps; possible waitlist if funds exhausted.",
    "forms": ["MedQUEST application (online form 03701 or equivalent via portal); MSP-specific via MedQUEST"],
    "documents": ["Proof of income (SSI award, pay stubs, tax returns), assets (bank statements), Medicare card, ID (birth certificate/SSN), proof of residency, household size info."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Hawaii residents only",
    "regional_variations": "Administered uniformly statewide via MedQUEST; possible processing differences by island/district office (Oahu, Maui, etc.), but no specified variations.",
    "offices_or_providers": ["MedQUEST district offices on Oahu (Kapolei), Maui, Big Island, Kauai."]
  },
  "official_source": "https://medquest.hawaii.gov/content/medquest/en/members-applicants/get-started/programs.html",
  "gotchas": ["Outdated limits in sources (use 2026 figures, confirm with state as Hawaii higher); QI annual reapply + funding limits; income disregards ($20 general, wage/shelter deductions) often missed; assets include spouse even if not applying; auto-Extra Help but must confirm enrollment; differs from mainland by higher limits/no resource test in some states.[1][3][5][6]"],
  "data_shape_notes": "Tiered by income (QMB lowest, QI highest); Hawaii higher income/resource limits than federal; QI capped funding/first-come; benefits fixed by tier not household size beyond couple."
}

{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Household income at or below 200% of the Federal Poverty Guidelines for Hawaii. Automatic eligibility if any household member receives TANF or SSI. Example limits from Kauai provider (may vary by year): 1-person: $28,260; 2: $38,440; 3: $48,620; 4: $58,800; 5: $69,000; 6: $79,140; 7: $89,280; 8: $99,420; add $5,220 per additional person.[6][1][3]",
    "asset_limits": "No asset limits mentioned in Hawaii-specific sources.[1][3][5]",
    "other_requirements": ["Priority to elderly (60+), persons with disabilities, families with children (under 19 or 6 per some providers), high energy users, high energy burden households.[1][3][7]", "Homeowners, renters, mobile home owners eligible; single-family homes and multi-family up to 4 units.[4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free weatherization measures per Hawaii Priority List: low-flow showerheads/faucet aerators, CFL/LED lighting, advanced power strips, hybrid heat pump/solar water heaters, small/very large room ACs, refrigerator replacement. Includes energy efficiency education and in-home assessment.[3][1]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Oahu (Honolulu): Contact HCAP via https://www.hcapweb.org/weatherization-assistance-program/ or their site form.[1]", "Hawaii County (Hilo): Email wap@hceoc.net (PDF/DOC), mail or in-person to 47 Rainbow Drive, WAP Office Bldg 2, Hilo, HI 96720.[5]", "Kauai: Complete KEO Intake Form via https://keoinc.org/services/weatherization-assistance/.[6]", "Statewide admin: Hawaii Dept of Labor OCS at https://labor.hawaii.gov/ocs/service-programs-index/weatherization-assistance-program/.[3]", "No specific statewide phone listed; contact local providers."],
    "processing_time": "Not specified in sources.",
    "waitlist": "Limited applications due to funding; HCEOC notes limited approvals.[5]",
    "forms": ["KEO Intake Form (Kauai), HCEOC application (Hawaii County); no statewide form number.[5][6]"],
    "documents": ["Proof of income for all household members: paystubs (3 months), unemployment stubs, DHS 12-month benefit history (welfare/SNAP), SSI/SS letter or verification.[6][2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered statewide via subgrantees by county.",
    "regional_variations": "Different local providers: HCAP (Oahu/Honolulu), HCEOC (Hawaii County), KEO (Kauai); priority ages vary slightly (60+ statewide, 65+ or under-6 children in some brochures); apply via county-specific offices.[1][3][5][6][7]",
    "offices_or_providers": ["HCAP (Oahu), HCEOC (47 Rainbow Dr, Hilo), KEO (Kauai), state OCS.[1][3][5][6]"]
  },
  "official_source": "https://labor.hawaii.gov/ocs/service-programs-index/weatherization-assistance-program/",
  "gotchas": ["Funding-limited, so not all eligible get services; must apply via specific county provider, not centralized; automatic eligibility for TANF/SSI but still need to apply/contact local agency; priority tiers mean elderly may wait if high demand; verify current 200% FPG as they update annually.[1][3][5]", "Services free but only pre-approved measures from Hawaii list.[3]"],
  "data_shape_notes": "County-specific subgrantees handle applications; priority-based allocation with limited funding; income at 200% FPG or TANF/SSI auto-eligible; benefits from fixed Hawaii priority list."
}

{
