  },
  "application": {
    "methods": ["Phone: 808-586-7299 or toll-free 1-888-875-9229 (TTY: 1-866-810-4379)", "Website: https://www.hawaiiship.org (to request counseling or schedule presentation)", "In-person: Available if necessary with accommodations", "Virtual: Over phone or Zoom"][7][9][10],
    "processing_time": "Not specified; counseling scheduled upon contact.[10]",
    "waitlist": null,
    "forms": [],
    "documents": ["No specific documents required for initial counseling; may need Medicare-related info for detailed assistance."][10]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Local counselors available statewide via phone/Zoom; in-person by accommodation; no noted differences by region.[7][10]",
    "offices_or_providers": ["Administered statewide by Hawaii Department of Health, Executive Office on Aging."][6][8]
  },
  "official_source": "https://www.hawaiiship.org[6]",
  "gotchas": ["Not a direct service or financial benefit program—provides counseling and referrals only, not healthcare or payments.", "Volunteer-based with certified counselors; may involve scheduling.", "Often confused with Medicaid programs due to 'SHIP' association, but no eligibility tests like income/assets.", "Does not provide long-term care services directly; refers to options like MedQuest."[5][7][8]],
