{
  "name": "Long-Term Care Ombudsman Program (LTCOP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to any resident of a qualifying facility regardless of financial status.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must be a resident of a licensed long-term care facility in Hawaii, such as nursing homes, assisted living facilities, adult residential care homes (ARCH), community care foster family homes (CCFFH), expanded ARCH, hospice centers, or adult day care.[5][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including identifying, investigating, and resolving complaints made by or on behalf of residents; regular in-person facility visits; protection of health, safety, welfare, and rights; technical support for resident and family councils; information on obtaining services; timely responses to complaints; monitoring for abuse, neglect, and exploitation.[1][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-888-229-2231 (toll-free) or (808) 586-7268[4][6]", "Website: https://www.hi-ltc-ombudsman.org (for information and contact)[6]", "Email: lynn.niitani@doh.hawaii.gov[3]", "In-person: Contact via phone for facility visits or office at 250 S. Hotel St., Ste. 406, Honolulu, HI 96813[7]"],
    "processing_time": "Timely and responsive handling of complaints and concerns; no formal processing time specified as services are provided on-demand via advocacy visits and investigations.",
    "waitlist": null,
    "forms": ["No specific application form required for residents or families to receive services; contact directly to report issues or request assistance.[6]"],
    "documents": ["No documents needed to request assistance; ombudsmen maintain strict confidentiality and can proceed with oral consent documented in writing.[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services limited to residents in licensed long-term care facilities across Hawaii.",
    "regional_variations": "Contractors provide services on Neighbor Islands (e.g., West Hawaii); ombudsmen conduct regular visits statewide with potential travel by providers to facilities in designated areas.[2][6]",
    "offices_or_providers": ["Primary office: Executive Office on Aging, Department of Health, 250 S. Hotel St., Ste. 406, Honolulu, HI 96813[7]", "State Long-Term Care Ombudsman: John G. McDermott[4]"]
  },
  "official_source": "https://www.hi-ltc-ombudsman.org",
  "gotchas": ["This is not a direct service or financial aid program but pure advocacy for residents already in facilities—families cannot 'apply' their loved one into a facility through LTCOP.[6]", "Services are for current facility residents only, not for qualification into care or home-based care.[5]", "Strict confidentiality: Information shared is protected unless resident consents or required by law.[1][6]", "Not for volunteers (who must apply separately with training and checks).[3][4]"],
  "data_shape_notes": "no income or asset test; advocacy-only for residents of licensed LTC facilities statewide; on-demand complaint resolution rather than enrollment-based benefits"
}

